@inject ITicketService TicketService

<div class="ticket-dashboard">
    <!-- Top bar -->
    <div class="top-bar">
        <div class="search-box">
            <input type="text" placeholder="Search tickets by subject..." @bind="searchQuery" @bind:event="oninput" @onkeyup="OnSearchKeyUp" />
            <button @onclick="LoadTicketsAsync">Search</button>
        </div>
        <div class="status-tabs">
            @foreach (var tab in statusTabs)
            {
                <button class="tab @(statusFilter == tab.Value ? "active" : "")" @onclick="() => SetStatusFilter(tab.Value)">@tab.Label</button>
            }
        </div>
        <div class="priority-filter">
            <select @onchange="OnPriorityFilterChanged">
                @foreach (var p in priorityOptions)
                {
                    <option value="@p.Value" selected="@(priorityFilter == p.Value)">@p.Label</option>
                }
            </select>
        </div>
    </div>

    <!-- Main panels -->
    <div class="panels">
        <!-- Left panel -->
        <div class="left-panel">
            @if (tickets is null)
            {
                <p class="loading">Loading tickets...</p>
            }
            else if (tickets.Count == 0)
            {
                <p class="no-tickets">No tickets found.</p>
            }
            else
            {
                @foreach (var ticket in tickets)
                {
                    <div class="ticket-card @(selectedTicket?.Id == ticket.Id ? "active" : "")" @onclick="() => SelectTicketAsync(ticket)">
                        <div class="ticket-card-header">
                            <span class="priority-dot @GetPriorityClass(ticket.Priority)"></span>
                            <span class="ticket-subject">@ticket.Subject</span>
                        </div>
                        <div class="ticket-card-meta">
                            <span class="requester">@ticket.Requester</span>
                            <span class="time-ago">@GetRelativeTime(ticket.CreatedAt)</span>
                        </div>
                        <span class="status-badge @GetStatusClass(ticket.Status)">@ticket.Status</span>
                    </div>
                }
            }
        </div>

        <!-- Right panel -->
        <div class="right-panel">
            @if (selectedTicket is null)
            {
                <p class="placeholder">Select a ticket to view details</p>
            }
            else
            {
                <div class="detail-header">
                    <h2>@selectedTicket.Subject</h2>
                    <div class="detail-actions">
                        <select value="@selectedTicket.Status" @onchange="OnStatusChanged">
                            <option value="Open">Open</option>
                            <option value="In Progress">In Progress</option>
                            <option value="Resolved">Resolved</option>
                        </select>
                        <span class="priority-badge @GetPriorityClass(selectedTicket.Priority)">@selectedTicket.Priority</span>
