.ticket-dashboard {
    display: flex;
    flex-direction: column;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Top bar */
.top-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
    flex-wrap: wrap;
}

.search-box {
    display: flex;
    gap: 0.5rem;
}

.search-box input {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 220px;
}

.search-box button {
    padding: 0.4rem 0.75rem;
    border: none;
    background: #0078d4;
    color: white;
    border-radius: 4px;
    cursor: pointer;
}

.search-box button:hover {
    background: #106ebe;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.status-tabs .tab {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    background: white;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.status-tabs .tab.active {
    background: #0078d4;
    color: white;
    border-color: #0078d4;
}

.priority-filter select {
    padding: 0.4rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

/* Panels */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #e0e0e0;
    background: #f9f9f9;
}

.right-panel {
    width: 60%;
    overflow-y: auto;
    padding: 1.5rem;
}

.placeholder {
    color: #888;
    text-align: center;
    margin-top: 3rem;
    font-size: 1.1rem;
}

/* Ticket cards */
.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #edf4ff;
}

.ticket-card.active {
    background: #d6e8ff;
    border-left: 3px solid #0078d4;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #e53935;
}

.priority-high {
    background-color: #fb8c00;
}

.priority-medium {
    background-color: #fdd835;
}

.priority-low {
    background-color: #9e9e9e;
}

.ticket-subject {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    font-weight: 500;
    font-size: 0.95rem;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    margin-top: 0.25rem;
    font-size: 0.8rem;
    color: #666;
}

.status-badge {
    display: inline-block;
    margin-top: 0.35rem;
    padding: 0.15rem 0.5rem;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 500;
}

.status-open {
    background: #e3f2fd;
    color: #1565c0;
}

.status-in-progress {
    background: #fff3e0;
    color: #e65100;
}

.status-resolved {
    background: #e8f5e9;
    color: #2e7d32;
}

/* Detail view */
.detail-header h2 {
    margin: 0 0 0.5rem 0;
}

.detail-actions {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.detail-actions select {
    padding: 0.3rem 0.5rem;
