.comment-time {
    color: #888;
}

.comment-text {
    margin: 0;
    font-size: 0.9rem;
}

.no-comments {
    color: #888;
    font-style: italic;
}

/* Add comment */
.add-comment {
    margin-top: 1rem;
}

.add-comment textarea {
    width: 100%;
    min-height: 80px;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    resize: vertical;
